"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { apiRequest } from "@/lib/api";

export default function ProductsPage() {
  const [products, setProducts] = useState<any[]>([]);
  const [categories, setCategories] = useState<any[]>([]);
  const [minPrice, setMinPrice] = useState(0);
  const [maxPrice, setMaxPrice] = useState(10000);
  const [category, setCategory] = useState("");

  useEffect(() => {
    apiRequest("/categories").then(setCategories);
  }, []);

  useEffect(() => {
    const params = new URLSearchParams();

    if (category) params.append("category", category);
    params.append("minPrice", String(minPrice));
    params.append("maxPrice", String(maxPrice));

    apiRequest(`/products?${params.toString()}`).then(setProducts);
  }, [minPrice, maxPrice, category]);

  return (
    <main className="px-6 py-24 max-w-[1400px] mx-auto">
      <div className="grid grid-cols-[260px_1fr] gap-12">

        {/* FILTERS */}
        <aside>
          <p className="mb-4 text-sm uppercase opacity-60">
            Filter by
          </p>

          {/* PRICE FILTER */}
          <div className="mb-10">
            <p className="mb-3 text-sm">Price</p>

            <div className="space-y-4">
              <div>
                <label className="text-xs opacity-70">
                  Min ₹{minPrice}
                </label>
                <input
                  type="range"
                  min={0}
                  max={10000}
                  step={100}
                  value={minPrice}
                  onChange={(e) =>
                    setMinPrice(Number(e.target.value))
                  }
                  className="w-full"
                />
              </div>

              <div>
                <label className="text-xs opacity-70">
                  Max ₹{maxPrice}
                </label>
                <input
                  type="range"
                  min={0}
                  max={10000}
                  step={100}
                  value={maxPrice}
                  onChange={(e) =>
                    setMaxPrice(Number(e.target.value))
                  }
                  className="w-full"
                />
              </div>
            </div>
          </div>

          {/* CATEGORY */}
          <div>
            <p className="mb-3 text-sm">Category</p>
            <ul className="space-y-2 text-sm">
              <li
                className={!category ? "font-medium cursor-pointer" : "opacity-70 cursor-pointer"}
                onClick={() => setCategory("")}
              >
                All
              </li>

              {categories.map((c) => (
                <li
                  key={c.id}
                  className={
                    category === c.slug
                      ? "font-medium cursor-pointer"
                      : "opacity-70 cursor-pointer"
                  }
                  onClick={() => setCategory(c.slug)}
                >
                  {c.name}
                </li>
              ))}
            </ul>
          </div>
        </aside>

        {/* PRODUCTS GRID */}
        <section className="grid sm:grid-cols-2 lg:grid-cols-3 gap-12">
          {products.map((p) => (
            <Link key={p.id} href={`/products/${p.id}`}>
              <img
                src={p.image_base64}
                alt={p.name}
                className="aspect-[4/5] object-cover mb-3"
              />
              <p className="text-sm">{p.name}</p>
              <p className="text-sm opacity-70">₹{p.price}</p>
            </Link>
          ))}
        </section>
      </div>
    </main>
  );
}